<?php
namespace App\Http\Controllers\Api;
use App\Actions\{CreateMaterialPurchaseAction,DeleteMaterialPurchaseAction,UpdateMaterialPurchaseAction};use App\Http\Requests\MaterialPurchaseRequest;use App\Models\{MaterialPurchase,Project};use App\Http\Controllers\Controller;
class MaterialPurchaseController extends Controller{public function index(Project $project){$this->authorize('view',$project);return $project->materialPurchases()->with('items.material','tags')->latest('date')->get();} public function store(MaterialPurchaseRequest $r,Project $project,CreateMaterialPurchaseAction $a){$this->authorize('update',$project);return $a->execute($r->validated()+['project_id'=>$project->id]);} public function show(MaterialPurchase $purchase){$this->authorize('view',$purchase);return $purchase->load('items.material','tags');} public function update(MaterialPurchaseRequest $r,MaterialPurchase $purchase,UpdateMaterialPurchaseAction $a){$this->authorize('update',$purchase);return $a->execute($purchase,$r->validated());} public function destroy(MaterialPurchase $purchase,DeleteMaterialPurchaseAction $a){$this->authorize('delete',$purchase);$a->execute($purchase);return response()->noContent();}}
